  ('dietitian-moex-00523', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關兒童期氣喘（asthma）的營養治療建議，下列敘述何者錯誤？', '["富含單元不飽和脂肪酸的飲食降低體內氧化壓力", "補充維生素C有助於改善肺功能", "維持過重或輕度肥胖的BMI可減少氣喘發作", "高油脂飲食可能引起胃食道逆流（gastroesophageal reflux disease）而誘發氣喘"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00524', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關慢性阻塞性肺病（COPD）病人，下列敘述何者錯誤？', '["emphysema是屬於COPD的一種病症", "呼吸肌肉耗損，顯著影響換氣功能", "病人能量需求增加", "過度餵食後，常有酮酸中毒現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00525', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '「使用試劑或藥物，系統性治療癌症，這些試劑會干擾細胞週期的步驟或階段，特別是干擾DNA合成和癌細 胞的複製」，是屬於那一類抗腫瘤治療？', '["生物療法", "荷爾蒙療法", "化學療法", "放射線療法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00526', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關惡病質（cachexia）的敘述，下列何者正確？', '["是早期癌症病人常見的繼發診斷，病人呈蛋白質－熱量營養不良", "其特徵是體重逐漸加速流失、厭食、免疫下降和代謝異常", "會減少脂肪組織的損失，這與脂解速率的降低有關", "靜態能量消耗值（REE）下降，以保留身體能量和組織"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00527', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關癲癇（epilepsy）的營養治療建議，下列何者錯誤？', '["食物中脂質和非脂質（non-fat）的重量比可達4：1", "體重若快速增加可能不利治療飲食的效果", "營養素補充劑中糖含量很低可忽略不計", "服用碳酸氫鈉（sodium bicarbonate）可改善治療飲食使用初期的酸中毒症狀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00528', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '以左旋多巴（L-dopa）治療巴金森氏症（Parkinson''s Disease）的病人須留意那些營養問題？①避免由食物', '["①②", "③④", "①③", "②④"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00529', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '小於懷孕週齡（small for gestational age, SGA）的定義，是指胎兒體重小於同週齡胎兒體重生長曲線的 多少百分位？', '["20", "15", "10", "5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00530', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '衛生主管機關執行食品安全管制系統符合性稽查，對於未符合食品安全管制系統準則之食品業者，可依食品 安全衛生管理法第44條第1項規定開罰，下列敘述何者錯誤？', '["命其限期改正，屆期不改正，處新臺幣六萬元以上二億元以下罰鍰", "情節重大者，並得命其歇業、停業一定期間、廢止其公司、商業、工廠之全部或部分登記事項，或食品業 者之登錄", "經廢止登錄者，一年內不得再申請重新登錄", "處三年以下有期徒刑、拘役或新臺幣一百萬元以下罰金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00531', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者不是食品安全管制系統執行確認（Verification）之方法？', '["定期對產品取樣進行檢查，例如：微生物檢驗、製程檢查", "對監測 CCP 的儀器進行校正或精度檢查", "定期檢討所實施的食品安全管制系統計畫", "列出造成食品不安全的生物性、物理性及化學性的潛在危害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00532', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '食品安全衛生管理法中，有關食品安全會報之敘述，下列何者錯誤？', '["行政院應設食品安全會報，由衛生福利部部長擔任召集人", "各縣（市）政府也應設食品安全會報，召集人由各縣（市）政府首長擔任", "食品安全會報會議應至少三個月舉行一次", "食品安全會報成員包含專家學者及民間團體代表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
